1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — base premiums per item type
6	  it("empty item list yields premium of 5 G (just the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("a single plain sword quote yields 105 G (100 base + 5 fee)");
14	  it.todo("a single plain amulet quote yields 65 G");
15	  it.todo("a single plain staff quote yields 85 G");
16	  it.todo("a single plain potion quote yields 45 G");
17	
18	  // Components
19	  it.todo("a single rune yields 30 G (25 base + 5 fee)");
20	  it.todo("two runes yield 55 G (50 base + 5 fee)");
21	  it.todo("three alike runes form a block at 60 G base premium (65 G total)");
22	  it.todo("four runes yield 105 G (no block — block is exactly 3)");
23	  it.todo("three runes and three moonstones form two blocks: 120 G base (125 G total)");
24	  it.todo("two runes plus one moonstone yield 75 G base (no block)");
25	
26	  // Item-specific surcharges
27	  it.todo("a cursed sword adds 50% curse surcharge to its base premium");
28	  it.todo("a sword with enchantment level 5 adds 30% high-enchantment surcharge");
29	  it.todo("a sword with enchantment level 4 has no high-enchantment surcharge");
30	  it.todo("a cursed sword with enchantment 5 stacks both surcharges");
31	
32	  // Policy-wide modifiers
33	  it.todo("a 2-year customer receives a 20% loyalty discount on policy base");
34	  it.todo("first insurance adds 10% surcharge on policy base");
35	  it.todo("a follow-up contract gets a 15% discount on policy base");
36	
37	  // Multi-item modifier scope
38	  it.todo("cursed surcharge applies only to the cursed item, not the policy total");
39	
40	  // Rounding
41	  it.todo("premium rounds up in MHPCO's favor");
42	
43	  // Integration examples
44	  it.todo("newcomer with cursed sword yields 165 G");
45	  it.todo("long-standing customer's second contract with cursed enchantment-7 sword yields 160 G");
46	
47	  // Claim — base behaviors
48	  it.todo("standard sword damage of 500 G yields payout 400 G (after 100 G deductible)");
49	  it.todo("damage to a rune (250 G insurance) with damage 200 G yields payout 100 G");
50	  it.todo("damage to an item with enchantment ≥ 8 is reimbursed at 50% then deductible");
51	  it.todo("damage to a dragon-material item is fully reimbursed then deductible");
52	  it.todo("dragon material + high enchantment: 50% rule wins, then deductible");
53	  it.todo("deductible applies once per damage entry on multi-item incidents");
54	
55	  // Cap
56	  it.todo("payout is capped at twice the unmodified insurance sum across claims");
57	  it.todo("returns remainingCap after each claim");
58	
59	  // Multiple items of same type
60	  it.todo("two swords on a policy double the insurance sum");
61	  it.todo("more damages of a type than insured items rejects the claim");
62	
63	  // Error handling
64	  it.todo("quote with unknown item type rejects the scenario");
65	  it.todo("claim with damage on item not in policy rejects the scenario");
66	  it.todo("claim with negative damage amount rejects the scenario");
67	});
